mapper.select:
SELECT INQUIRY_ID AS inquiryId, USER_ID AS userId, TITLE AS title, CONTENT AS content, STATUS AS status, ANSWER_CONTENT AS answerContent, ANSWERED_AT AS answeredAt, CREATED_AT AS createdAt FROM LQ_INQUIRY
AND ( TITLE LIKE '%' || #{keyword} || '%' OR CONTENT LIKE '%' || #{keyword} || '%' )
AND STATUS = #{status}
AND USER_ID = #{userId}
ORDER BY INQUIRY_ID DESC
